insert into legacy.sent_emails (email_id, sent_at, recipient, subject, body)
values
  ('1', '2025-02-24 20:48:31.86737', 'jasonmacpei@hotmail.com', 'Test again', '<p>This is a test again.</p>'),
  ('2', '2025-02-24 20:49:44.215921', 'mandymacdonald@hotmail.com, jasonmacpei@hotmail.com', 'This is another test', '<p>Hey for testing...</p>
<p>&nbsp;</p>
<h1><strong>HELLO!!!!</strong></h1>'),
  ('3', '2025-02-24 21:21:42.011152', 'jasonmacpei@hotmail.com', 'This is a test', '<p>This is a test</p>'),
  ('4', '2025-02-25 18:50:49.159403', 'jeffgwalker@gmail.com, jasonmacpei@hotmail.com, cbdreambasketball@gmail.com, outdoorhoopsns@gmail.com, lucas.wide@gmail.com, nxtlevelball@hotmail.com, crys_790@hotmail.com, sportsadditive@gmail.com, jillpowell17@gmail.com, royals@fallriverroyals.ca, chrishuggan@gmail.com, evolutionbballacademy@gmail.com', 'Spring Shootout – Initial Tournament Update & Next Steps', '<p class="p1">Dear Coaches and Team Managers,</p>
<p class="p2">&nbsp;</p>
<p class="p1">Thank you for expressing interest in the Spring Shootout! We&rsquo;re excited about this year&rsquo;s tournament and appreciate your involvement.</p>
<p class="p2">&nbsp;</p>
<p class="p1">We are currently working on finalizing the number of teams for each division. As it stands, we have:</p>
<p class="p3">&bull;<span class="Apple-tab-span">&nbsp;</span><span class="s1"><strong>6 teams in U11</strong></span>&nbsp;(aiming for 8)</p>
<p class="p3">&bull;<span class="Apple-tab-span">&nbsp;</span><span class="s1"><strong>5 teams in U12</strong></span>&nbsp;(aiming for 8)</p>
<p class="p3">&bull;<span class="Apple-tab-span">&nbsp;</span><span class="s1"><strong>10 teams in U13</strong></span>&nbsp;(good to go!)</p>
<p class="p2">&nbsp;</p>
<p class="p1">If you know of any teams that might be interested, please share the&nbsp;<span class="s1"><strong>tournament website</strong></span>&nbsp;with them&mdash;we&rsquo;d love to fill those final spots!</p>
<p class="p2">&nbsp;</p>
<p class="p1">A couple of important notes:</p>
<p class="p3">&bull;<span class="Apple-tab-span">&nbsp;</span><span class="s1"><strong>Hotel bookings</strong></span>&nbsp;&ndash; Please&nbsp;<span class="s1"><strong>hold off</strong></span>&nbsp;on booking accommodations. We will provide detailed booking instructions in early March.</p>
<p class="p3">&bull;<span class="Apple-tab-span">&nbsp;</span><span class="s1"><strong>Payment</strong></span>&nbsp;&ndash; We will be collecting team fees by&nbsp;<span class="s1"><strong>March 15</strong></span>. Payment instructions will be sent out in the next week or so.</p>
<p class="p2">&nbsp;</p>
<p class="p1">If you have any questions, feel free to reach out to me at&nbsp;<span class="s1"><strong>jason@springshootout.ca</strong></span>.</p>
<p class="p2">&nbsp;</p>
<p class="p1">Looking forward to a great tournament!</p>
<p class="p2">&nbsp;</p>
<p class="p1">Best,</p>
<p class="p4"><strong>Jason MacDonald</strong></p>
<p class="p1">Spring Shootout Tournament Organizer</p>'),
  ('5', '2025-03-20 23:03:31.224281', 'jasonmacpei@hotmail.com, mandymacdonald@hotmail.com, cbdreambasketball@gmail.com, outdoorhoopsns@gmail.com, lucas.wide@gmail.com, nxtlevelball@hotmail.com, crys_790@hotmail.com, sportsadditive@gmail.com, jillpowell17@gmail.com, royals@fallriverroyals.ca, chrishuggan@gmail.com, evolutionbballacademy@gmail.com, jeffgwalker@gmail.com, erin.mcaleenan@unb.ca, peter.kelly@unb.ca, hello@test.com, karen@cameronlawpei.com, ellahoyt4@icloud.com', 'Spring Shootout Tournament - Hotel Booking and Payment Reminder', 'Hi Coaches and Managers,
I hope your spring season is going well! We''re about six weeks away from our Spring Shootout Tournament, and I wanted to pass along some important updates:
Hotel Booking You can now contact our tournament hotels to arrange accommodations. Coaches or managers should call directly to reserve a block of rooms for your team under "Island Aces Girls Spring Shootout." After the block is set, parents can then individually book their rooms from your team''s reserved block. The tournament rate at both hotels is $189 plus tax per night.
Hampton Inn &amp; Suites 300 Capital Drive, Charlottetown, PEI, C1E 2N1Phone: (902) 368-3551

55 standard rooms with two queen beds
20 standard rooms with one king bed

Holiday Inn Express &amp; Suites 200 Capital Drive, Charlottetown, PE, C1E 2E8Phone: (902) 892-1201

90 standard rooms with two queen beds
10 standard rooms with one king bed

Tournament Payments Payments are now being accepted. The registration fee of $425 is due by April 1 via e-transfer to: jasonmacpei@hotmail.com. If your team anticipates any difficulty meeting this payment deadline, please feel free to reach out privately, and we can discuss alternative arrangements.
Team Registrations We currently have:

U11: 6 teams
U12: 6 teams
U13: 11 teams

I''d love to add one more team to U13 and ideally two more teams each in U11 and U12, bringing each division to 8 teams. Please forward our tournament info to any contacts who might be interested!
If you have any questions or need further assistance, please let me know.
Looking forward to an exciting event!
Thanks, Jason
ps...I was having some issue with jason@springshootout.ca.&nbsp; These have been resolved, but there is a chance I didn''t get some emails, so if I missed responding to one of your emails, feel free to resend, or call or text at (902) 626-1936.'),
  ('6', '2025-03-26 20:32:32.134454', 'mandymacdonald@hotmail.com, jasonmacpei@hotmail.com, cbdreambasketball@gmail.com, outdoorhoopsns@gmail.com, lucas.wide@gmail.com, nxtlevelball@hotmail.com, crys_790@hotmail.com, sportsadditive@gmail.com, jillpowell17@gmail.com, royals@fallriverroyals.ca, chrishuggan@gmail.com, evolutionbballacademy@gmail.com, jeffgwalker@gmail.com, erin.mcaleenan@unb.ca, peter.kelly@unb.ca, hello@test.com, karen@cameronlawpei.com, ellahoyt4@icloud.com, johnmaclellan19@gmail.com', 'Hotel Deadline - April 2', 'Hi Everyone,
Thanks to all those that have sent in your registration - those that didn''t, just a reminder that April 1 is the deadline for holding your spot.
Also, the hotel wants all hotel rooms booked by April 1. &nbsp;If you aren''t planning on staying at one of the tournament hotels, please let me know so that I don''t need to worry about room numbers for you.
That''s is for now.
As always, if you have any questions, please let me know.
Best,
Jason.'),
  ('7', '2025-04-02 14:57:02.385074', 'jeffgwalker@gmail.com, jasonmacpei@hotmail.com, cbdreambasketball@gmail.com, outdoorhoopsns@gmail.com, lucas.wide@gmail.com, nxtlevelball@hotmail.com, crys_790@hotmail.com, sportsadditive@gmail.com, jillpowell17@gmail.com, royals@fallriverroyals.ca, chrishuggan@gmail.com, evolutionbballacademy@gmail.com, erin.mcaleenan@unb.ca, peter.kelly@unb.ca, hello@test.com, karen@cameronlawpei.com, ellahoyt4@icloud.com, johnmaclellan19@gmail.com, h.delaney@outlook.com, fewerdarlene@gmail.com, nickrobichaud@hotmail.com, jilly.flanny@gmail.com', 'Hotel Rooms', 'Hi All,
Just a quick reminder that today is the last day for hotel bookings. &nbsp;If this is a problem, reach out to me ASAP.
As well, there is a couple that I haven''t heard from in terms of the registration fee..please send in or reach out to me as soon as you can so I can confirm your spot. &nbsp;
Regards,
Jason.');

insert into legacy.welcome_emails (id, subject, body, created_at)
values
  ('1', 'Welcome to Spring Shootout 2025', 'Hi everyone,

Welcome to the second annual Spring Shootout 2025!

We’re gearing up for another great tournament. Registrations are rolling in, but we’re still looking for teams in the U11 and U12 divisions. If you know any teams that might be interested, please share our website: www.springshootout.ca.

A few important notes:
	•	Hotel bookings – Please hold off on booking accommodations for now. We’ll provide detailed booking instructions in early March.
	•	Payment – Team fees will be due by March 15. Payment instructions will be sent out next week.

Please note that this email does not guarantee entry into the tournament. Your spot will be secured once payment is received.

If you have any questions, feel free to reach out to me at jason@springshootout.ca.

Looking forward to an exciting tournament!

Best,
Jason MacDonald
Spring Shootout Tournament Organizer', '2025-02-26 09:49:47.569701');


