insert into public.email_templates (
  legacy_welcome_email_id,
  event_id,
  slug,
  subject,
  text_body,
  is_active
)
select
  data.legacy_welcome_email_id,
  e.id,
  data.slug,
  data.subject,
  data.text_body,
  true
from (
  select 1::integer as legacy_welcome_email_id, 'legacy-welcome-email-2025'::text as slug, 'Welcome to Spring Shootout 2025'::text as subject, 'Hi everyone,

Welcome to the second annual Spring Shootout 2025!

We’re gearing up for another great tournament. Registrations are rolling in, but we’re still looking for teams in the U11 and U12 divisions. If you know any teams that might be interested, please share our website: www.springshootout.ca.

A few important notes:
	•	Hotel bookings – Please hold off on booking accommodations for now. We’ll provide detailed booking instructions in early March.
	•	Payment – Team fees will be due by March 15. Payment instructions will be sent out next week.

Please note that this email does not guarantee entry into the tournament. Your spot will be secured once payment is received.

If you have any questions, feel free to reach out to me at jason@springshootout.ca.

Looking forward to an exciting tournament!

Best,
Jason MacDonald
Spring Shootout Tournament Organizer'::text as text_body, 'spring-shootout-2025'::text as event_slug
) as data
join public.events e on e.slug = data.event_slug
on conflict (legacy_welcome_email_id) do update
set
  event_id = excluded.event_id,
  slug = excluded.slug,
  subject = excluded.subject,
  text_body = excluded.text_body,
  is_active = excluded.is_active;

commit;
